{"command": "cd /tmp/sv-0aab18848d484f19a99ba8a6d8d0c778/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_versions(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw['topLevelPackages']:
                key = (pname, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_versions(baseline)
a = get_versions(after)

print('=== CHANGES ===')
changes = False
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key, 'MISSING')
    av = a.get(key, 'MISSING')
    if bv != av:
        changes = True
        print(f'{key[0]} | {key[1]} | {key[2]} | {bv} -> {av}')

if not changes:
    print('(none)')

print()
print('=== UNCHANGED ===')
for key in sorted(b.keys()):
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        print(f'{key[0]} | {key[1]} | {key[2]} | {bv}')
"", "description": "Compare baseline vs after-CPM packages", "initial_wait": 10}
